### Why is this happening?
The website likely has a script in the `<head>` or at the bottom of the `<body>` that looks like this:
```javascript
document.addEventListener('keydown', function(e) {
    if (e.ctrlKey && e.shiftKey && e.key === 'I') {
        e.preventDefault(); // This stops the shortcut from working
    }
});
```
This is often done to protect intellectual property or prevent automated scraping, though it is annoying for developers.

**Example (JavaScript - Dynamic):**
```javascript
function makeItQuack(obj) {
  // We don't check if obj is a 'Duck' class.
  // We just check if it has a 'quack' method.
  if (typeof obj.quack === 'function') {
    obj.quack();
  }
}

class Duck {
  quack() { console.log("Quack!"); }
}

class Robot {
  quack() { console.log("Beep Boop!"); }
}

**Example (TypeScript):**
```typescript
interface Duck {
  quack(): void;
}

function makeItQuack(obj: Duck) {
  obj.quack();
}

class Duck {
  quack() { console.log("Quack!"); }
}

class Robot {
  quack() { console.log("Beep Boop!"); }
}

**Example:**
```typescript
interface Duck {
  quack(): void;
}

class Duck {
  quack() { console.log("Quack!"); }
}

class Robot {
  quack() { console.log("Beep Boop!"); }
}

// TypeScript accepts 'Robot' here because it has the 'quack' method.
// It doesn't matter that Robot doesn't say "implements Duck".
function makeItQuack(obj: Duck) {
  obj.quack();
}

